#define N_PARTICLES 200
#define PARTICLES_RESAMPLED 50 // # of particles resampeld

class Localization {
public:
    // Simulation Testing
    double PAR_MM_SIMULATE = 0.0;
    double IMU_SIMULATE = 0.0;
    double LEFT_SENSOR_SIMULATE = 0.0;
    double RIGHT_SENSOR_SIMULAR = 0.0;

    Pose real_pose;
    double max_error = 0.0;

private:
    // For particles
    Pose particles[N_PARTICLES] = {};
    double weights[N_PARTICLES] = {};

    std::default_random_engine gen;
    std::normal_distribution<double> linear_random{0.0, 5.0}; // Mean is 1, std Dev is 0.01
    std::normal_distribution<double> angular_random{0.0, 0.01}; // Mean is 1, std Dev is 0.01
    std::normal_distribution<double> resample_linear_random{0.0, 0.0}; // Mean is 1, std Dev is 0.01
    std::normal_distribution<double> resample_angular_random{0.0, 1.0}; // Mean is 1, std Dev is 0.01


    // For Odom
    static constexpr double DIST_PARA = 0.0;
    Pose delta_pos;

    // For color sensor
    Vector color_l_pos{20, 20};
    Vector color_r_pos{-20, 20};

    double sigma = 10.0; // Used for error in color sensors
    
    void simulate_pos(int count);

private:
    Pose pos;

    void update_particles(); // Uses odom to move particles

    void set_particle_weights(); // Assigns weights based on light sensors

    void resample_particles(); // Resamples Particles

public:

    // Setup
    void start(unsigned long interval_us = 5000); // default 5ms


    void reset(Pose pos);
    Pose getPose();

    // Function to run it
    friend void run_localization();
};

// Single global object
extern Localization positioning;